import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.BYlK8ftn.js";const b=JSON.parse('{"title":"Black Crown Pass","description":"","frontmatter":{},"headers":[],"relativePath":"guide/worlds/black-crown-pass.md","filePath":"guide/worlds/black-crown-pass.md","lastUpdated":1781991869000}'),o={name:"guide/worlds/black-crown-pass.md"};function i(s,t,n,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="black-crown-pass" tabindex="-1">Black Crown Pass <a class="header-anchor" href="#black-crown-pass" aria-label="Permalink to &quot;Black Crown Pass&quot;">​</a></h1><p><strong>Zone role:</strong> Mountain lands, villain fortress approach, vertical combat map.</p><p><strong>Design promise:</strong> A dangerous climb toward a hostile fort where the same geometry supports two fantasies: assault the villain&#39;s stronghold, or defend it as the villain&#39;s faction.</p><h2 id="lore" tabindex="-1">Lore <a class="header-anchor" href="#lore" aria-label="Permalink to &quot;Lore&quot;">​</a></h2><p>Black Crown Pass is older than the current war. The fort at the top was built by a dead kingdom that carved wells into the mountain and locked its inner doors from the outside. Nobody agrees why. Shepherds say the wells still echo with voices below the snow line. Empire officers say that is superstition. The villain says nothing and keeps the deepest gate barred.</p><p>Caravans do not travel the pass willingly. They end up here after raids, broken wheels, or false guides. Prisoners are kept in cages in the outer yard until they can be ransomed, recruited, or marched deeper into the keep. From below, the broken crown tower is visible for miles, which is exactly why the villain keeps signal fires lit there after every raid.</p><h2 id="mood-and-visual-language" tabindex="-1">Mood and visual language <a class="header-anchor" href="#mood-and-visual-language" aria-label="Permalink to &quot;Mood and visual language&quot;">​</a></h2><ul><li>Grey stone, snow patches, black banners, cold blue shadows, orange signal fire.</li><li>The fortress should dominate the view from every lower route.</li><li>Mountain geometry must look dangerous without making the controller miserable: broad ledges, readable ramps, clear blocker rails.</li><li>Villain props should feel scavenged and intimidating: cages, spikes, patched barricades, stolen caravan wood.</li></ul><h2 id="player-facing-flow" tabindex="-1">Player-facing flow <a class="header-anchor" href="#player-facing-flow" aria-label="Permalink to &quot;Player-facing flow&quot;">​</a></h2><ol><li>Start at the lower switchback with the fort visible above.</li><li>Choose the safer road, the goat trail flank, or a risky bridge route.</li><li>Fight or avoid patrol pairs positioned on elevation differences.</li><li>Reach the outer yard and decide whether to free prisoners, raid supplies, or open a defense route.</li><li>Use the keep gate as a future expansion boundary.</li></ol><h2 id="_20-by-20-text-map" tabindex="-1">20-by-20 text map <a class="header-anchor" href="#_20-by-20-text-map" aria-label="Permalink to &quot;20-by-20 text map&quot;">​</a></h2><p>Each row contains 20 cells. North is row 01, west is column 01.</p><table tabindex="0"><thead><tr><th>Symbol</th><th>Meaning</th></tr></thead><tbody><tr><td><code>^</code></td><td>Cliff or steep mountain wall</td></tr><tr><td><code>r</code></td><td>Walkable road / switchback</td></tr><tr><td><code>g</code></td><td>Goat trail flank</td></tr><tr><td><code>b</code></td><td>Bridge</td></tr><tr><td><code>v</code></td><td>Ravine / fall boundary</td></tr><tr><td><code>F</code></td><td>Fort wall or yard</td></tr><tr><td><code>K</code></td><td>Inner keep gate</td></tr><tr><td><code>C</code></td><td>Prison cages</td></tr><tr><td><code>B</code></td><td>Barricades</td></tr><tr><td><code>S</code></td><td>Signal fire</td></tr><tr><td><code>T</code></td><td>Broken crown tower</td></tr><tr><td><code>A</code></td><td>Avalanche scar / boulder arena</td></tr><tr><td><code>W</code></td><td>Broken wagon debris</td></tr><tr><td><code>.</code></td><td>Snowy open ground</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Row</th><th>20-cell map</th></tr></thead><tbody><tr><td>01</td><td><code>^^^^^^TTTTFFFF^^^^^^</code></td></tr><tr><td>02</td><td><code>^^^^^TTTSFFFFFK^^^^^</code></td></tr><tr><td>03</td><td><code>^^^^..TTFFFFCCF^^^^^</code></td></tr><tr><td>04</td><td><code>^^^...FFFFFCCFF^^^^^</code></td></tr><tr><td>05</td><td><code>^^^..BFFFFBBBB..^^^^</code></td></tr><tr><td>06</td><td><code>^^..BB...rr....^^^^^</code></td></tr><tr><td>07</td><td><code>^..B....rrr..^^^^^^^</code></td></tr><tr><td>08</td><td><code>^..vvvvbbrr..^^^^^^^</code></td></tr><tr><td>09</td><td><code>^^.vvvvvbr...gg^^^^^</code></td></tr><tr><td>10</td><td><code>^^^vvvv..r..ggg^^^^^</code></td></tr><tr><td>11</td><td><code>^^^^....rr..g..^^^^^</code></td></tr><tr><td>12</td><td><code>^^^..AAArr..g..^^^^^</code></td></tr><tr><td>13</td><td><code>^^..AAAArr.....^^^^^</code></td></tr><tr><td>14</td><td><code>^..AAA..r..W...^^^^^</code></td></tr><tr><td>15</td><td><code>^......rr.WW..^^^^^^</code></td></tr><tr><td>16</td><td><code>^^....rr.....^^^^^^^</code></td></tr><tr><td>17</td><td><code>^^^..rr....^^^^^^^^^</code></td></tr><tr><td>18</td><td><code>^^^^rr..^^^^^^^^^^^^</code></td></tr><tr><td>19</td><td><code>^^^rr..^^^^^^^^^^^^^</code></td></tr><tr><td>20</td><td><code>^rrr...^^^^^^^^^^^^^</code></td></tr></tbody></table><h2 id="landmark-briefs" tabindex="-1">Landmark briefs <a class="header-anchor" href="#landmark-briefs" aria-label="Permalink to &quot;Landmark briefs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Landmark</th><th>Player use</th><th>Implementation notes</th></tr></thead><tbody><tr><td>Broken crown tower</td><td>Main silhouette, signal fire platform</td><td>Visible from rows 20, 15, 10, and yard entrance.</td></tr><tr><td>Hanging bridge</td><td>Traversal risk and route choice</td><td>Start as a wide bridge with rails; visual danger can exceed mechanical danger.</td></tr><tr><td>Avalanche scar</td><td>Mid-map combat arena</td><td>Boulders provide cover and break charge lines.</td></tr><tr><td>Prison cages</td><td>Objective anchor and moral pressure</td><td>Place near yard edge so the player sees prisoners before entering the keep.</td></tr><tr><td>Inner keep gate</td><td>Expansion boundary</td><td>Large locked door; no interior required for first map.</td></tr></tbody></table><h2 id="faction-pressure" tabindex="-1">Faction pressure <a class="header-anchor" href="#faction-pressure" aria-label="Permalink to &quot;Faction pressure&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Faction</th><th>Presence</th><th>Behavior</th></tr></thead><tbody><tr><td>Villain forces</td><td>Fort yard, patrol road, tower</td><td>Defend high ground, retreat upward, use prisoners as stakes.</td></tr><tr><td>Empire</td><td>Lower road or assault wave</td><td>Can become attackers against the fort in a three-faction fight.</td></tr><tr><td>Human caravaners</td><td>Cages and broken wagons</td><td>Rescue targets, later reputation and reward source.</td></tr><tr><td>Forest Elves</td><td>Rare rescue ally or scout</td><td>Uses goat trail rather than main road.</td></tr></tbody></table><h2 id="encounter-set-pieces" tabindex="-1">Encounter set pieces <a class="header-anchor" href="#encounter-set-pieces" aria-label="Permalink to &quot;Encounter set pieces&quot;">​</a></h2><ul><li><strong>Lower ambush:</strong> two villain soldiers attack near broken wagon debris while a lookout retreats upward.</li><li><strong>Avalanche arena:</strong> boulders split melee movement and let the player break line of sight.</li><li><strong>Bridge standoff:</strong> enemy on the far side delays the player while another patrol approaches from the goat trail.</li><li><strong>Prison yard:</strong> cages create a choice between freeing prisoners and pushing toward the keep gate.</li><li><strong>Defense variant:</strong> if the player is villain-aligned, Empire attackers move from rows 20 to 05 while the player uses barricades and the tower.</li></ul><h2 id="traversal-and-camera-notes" tabindex="-1">Traversal and camera notes <a class="header-anchor" href="#traversal-and-camera-notes" aria-label="Permalink to &quot;Traversal and camera notes&quot;">​</a></h2><ul><li>Roads and goat trails should be wider than their art implies. Use cliff meshes outside the walkable path to create danger visually.</li><li>The third-person camera will be stressed by walls on one side and ravine on the other. Greybox camera tests should happen before art placement.</li><li>Avoid true fall damage in the first version. Ravines can be blocked by low collision rails hidden as rocks, snow banks, or broken fence.</li><li>Fort yard should be broad enough for at least five NPCs plus the player.</li></ul><h2 id="streaming-and-save-notes" tabindex="-1">Streaming and save notes <a class="header-anchor" href="#streaming-and-save-notes" aria-label="Permalink to &quot;Streaming and save notes&quot;">​</a></h2><ul><li>Suggested cells: <code>black_crown_lower_road</code>, <code>black_crown_avalanche</code>, <code>black_crown_bridge</code>, <code>black_crown_outer_yard</code>, <code>black_crown_tower</code>.</li><li>Save payload should track freed prisoners, opened yard barriers, and whether the tower signal fire is lit.</li><li>The keep gate is a clean streaming boundary for future interiors.</li><li>Defense and assault variants can share geometry but swap spawn tables and objective markers.</li></ul><h2 id="asset-list" tabindex="-1">Asset list <a class="header-anchor" href="#asset-list" aria-label="Permalink to &quot;Asset list&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Asset</th><th>Priority</th><th>Notes</th></tr></thead><tbody><tr><td>Mountain rock kit</td><td>High</td><td>Needs broad collision-friendly pieces.</td></tr><tr><td>Fort wall and gate kit</td><td>High</td><td>Main zone identity and expansion boundary.</td></tr><tr><td>Prison cages</td><td>High</td><td>Objective anchor.</td></tr><tr><td>Rope bridge</td><td>Medium</td><td>Traversal set piece; can share with forest variant only if restyled.</td></tr><tr><td>Broken wagon debris</td><td>Medium</td><td>Connects pass to caravan loop.</td></tr><tr><td>Barricades</td><td>Medium</td><td>Used in assault and defense variants.</td></tr><tr><td>Signal fire</td><td>Low</td><td>Strong atmosphere, simple interaction later.</td></tr><tr><td>Snow patches</td><td>Low</td><td>Cheap visual breakup.</td></tr></tbody></table><h2 id="open-implementation-questions" tabindex="-1">Open implementation questions <a class="header-anchor" href="#open-implementation-questions" aria-label="Permalink to &quot;Open implementation questions&quot;">​</a></h2><ul><li>Should the villain faction start inside the fort, or still climb the pass in an introductory mission?</li><li>Do rescued prisoners follow the player immediately, or become a delayed reward resolved after leaving the map?</li><li>How should the map handle defeat near cliffs if fall damage is not implemented?</li></ul>',28)])])}const p=e(o,[["render",i]]);export{b as __pageData,p as default};
